"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { NeumorphicInput } from "@/components/neumorphic/NeumorphicInput";
import { NeumorphicButton } from "@/components/neumorphic/NeumorphicButton";
import { useAuthStore } from "@/features/auth/stores/useAuthStore";
import { useTrip } from "@/features/trips/hooks/useTrip";
import { useAddCost } from "@/features/finances/hooks/useCosts";
import type { CostFormProps } from "./CostForm.types";
import { CategoryCost } from "@/types/models";

const schema = z.object({
  title: z.string().min(1, "El t├¡tulo es requerido"),
  amount: z.number().positive("El monto debe ser num├®rico y positivo"),
  date: z.string().min(1, "La fecha es requerida"),
  category: z.enum([
    "accommodation",
    "transport",
    "food",
    "general",
    "health",
    "equipment",
    "activity",
    "other",
  ]),
  splitType: z.enum(["equal", "custom"]),
});

type FormData = z.infer<typeof schema>;

export function CostForm({ tripId, onSuccess, onCancel }: CostFormProps) {
  const { currentUser } = useAuthStore();
  const { data: trip } = useTrip(tripId);
  const addCostMutation = useAddCost(tripId);

  const {
    register,
    handleSubmit,
    watch,
    formState: { errors },
  } = useForm<FormData>({
    resolver: zodResolver(schema),
    defaultValues: {
      category: "general",
      splitType: "equal",
      date: new Date().toISOString().split("T")[0],
    },
  });

  const splitType = watch("splitType");
  const baseAmount = watch("amount") || 0;

  // For custom split, we store { [userId]: amount }
  const [customSplit, setCustomSplit] = useState<Record<string, number>>({});

  const handleCustomSplitChange = (uid: string, value: string) => {
    setCustomSplit((prev) => ({
      ...prev,
      [uid]: Number(value),
    }));
  };

  const onSubmit = (data: FormData) => {
    if (!currentUser) return;

    const participants = trip?.participantIds || [currentUser.uid];

    // Auto-calculate equal split
    let finalSplit: Record<string, number> = {};

    if (data.splitType === "equal") {
      const perPerson = Number((data.amount / participants.length).toFixed(2));
      participants.forEach((uid) => {
        finalSplit[uid] = perPerson;
      });
      // Adjust the first one for any rounding error to match exact total
      const totalAllocated = perPerson * participants.length;
      if (totalAllocated !== data.amount) {
        finalSplit[participants[0]] += Number((data.amount - totalAllocated).toFixed(2));
      }
    } else {
      finalSplit = customSplit;
      // Validate custom split matches total
      const customTotal = Object.values(finalSplit).reduce((a, b) => a + b, 0);
      if (Math.abs(customTotal - data.amount) > 0.01) {
        alert(
          `La suma del split custom (${customTotal}) no coincide con el total (${data.amount}).`
        );
        return;
      }
    }

    addCostMutation.mutate(
      {
        userId: currentUser.uid,
        title: data.title,
        amount: data.amount,
        currency: trip?.currency || "USD",
        date: new Date(data.date),
        category: data.category as CategoryCost,
        paidBy: { [currentUser.uid]: data.amount }, // App assumes current user paid 100% for MVP
        splitTo: finalSplit,
        linkedTo: null, // For MVP simplified directly, but could add combo box
      },
      {
        onSuccess: () => {
          onSuccess?.();
        },
      }
    );
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <NeumorphicInput
          label="T├¡tulo/Concepto"
          {...register("title")}
          error={errors.title?.message}
        />

        <NeumorphicInput
          label={`Monto Total (${trip?.currency || "USD"})`}
          type="number"
          step="0.01"
          {...register("amount", { valueAsNumber: true })}
          error={errors.amount?.message}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <NeumorphicInput
          label="Fecha"
          type="date"
          {...register("date")}
          error={errors.date?.message}
        />

        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
            Categor├¡a
          </label>
          <select
            {...register("category")}
            className="w-full px-4 py-3 rounded-2xl bg-gray-50 dark:bg-gray-800 
                          border border-gray-200 dark:border-gray-700 text-gray-900 
                          dark:text-white focus:outline-none focus:ring-2 focus:ring-brand-500
                          shadow-inner"
          >
            <option value="accommodation">Alojamiento</option>
            <option value="transport">Transporte</option>
            <option value="food">Comida / Restaurante</option>
            <option value="activity">Actividad / Entrada</option>
            <option value="health">Salud / M├®dico</option>
            <option value="equipment">Equipamiento</option>
            <option value="general">General</option>
          </select>
        </div>
      </div>

      <div className="mt-6 pt-6 border-t border-gray-100 dark:border-gray-800">
        <h4 className="font-semibold text-gray-800 dark:text-gray-200 mb-3">
          Divisi├│n del Costo (Split)
        </h4>

        <div className="flex gap-4 mb-4">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              value="equal"
              {...register("splitType")}
              className="accent-brand-500"
            />
            <span className="text-sm dark:text-gray-300">Partes iguales</span>
          </label>
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="radio"
              value="custom"
              {...register("splitType")}
              className="accent-brand-500"
            />
            <span className="text-sm dark:text-gray-300">Montos espec├¡ficos</span>
          </label>
        </div>

        {splitType === "custom" && trip?.participantIds && (
          <div className="space-y-3 p-4 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border border-gray-100 dark:border-gray-800">
            <p className="text-xs text-gray-500 mb-2">
              Ingresa cu├ínto debe poner cada participante de los {baseAmount}.
            </p>
            {trip.participantIds.map((uid) => (
              <div key={uid} className="flex items-center justify-between">
                <span className="text-sm dark:text-gray-300 font-medium">
                  {uid === currentUser?.uid ? "T├║" : `ID: ${uid.substring(0, 6)}...`}
                </span>
                <div className="w-1/2">
                  <NeumorphicInput
                    type="number"
                    step="0.01"
                    placeholder="0.00"
                    value={customSplit[uid] || ""}
                    onChange={(e) => handleCustomSplitChange(uid, e.target.value)}
                  />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="flex justify-end gap-3 mt-8">
        {onCancel && (
          <NeumorphicButton variant="secondary" onClick={onCancel} type="button">
            Cancelar
          </NeumorphicButton>
        )}
        <NeumorphicButton variant="primary" type="submit" disabled={addCostMutation.isPending}>
          {addCostMutation.isPending ? "Guardando..." : "Guardar Gasto"}
        </NeumorphicButton>
      </div>
    </form>
  );
}

import { collection, doc, getDocs, updateDoc, deleteDoc, serverTimestamp, setDoc } from "firebase/firestore";
import { db } from "@/lib/firebase";
import type { AccommodationConfirmed, TransportConfirmed, InventoryConfirmed } from "@/types/models";
import { proposalsService } from "@/features/proposals/api/proposalsService";
import { AccommodationInput, TransportInput, InventoryInput } from "../types/logisticsSchemas";

import { toDate } from "@/utils/date-utils";

const TRIPS_COLLECTION = "trips";


export const logisticsService = {
  // ACCOMMODATION
  async getAccommodations(tripId: string): Promise<AccommodationConfirmed[]> {
    const q = collection(db, `${TRIPS_COLLECTION}/${tripId}/accommodation_confirmed`);
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => {
      const data = doc.data();
      return {
        ...data,
        id: doc.id,
        checkIn: toDate(data.checkIn) || new Date(),
        checkOut: toDate(data.checkOut) || new Date(),
        createdAt: toDate(data.createdAt) || new Date(),
      } as unknown as AccommodationConfirmed;
    }).sort((a, b) => ((a.checkIn as Date)?.getTime() || 0) - ((b.checkIn as Date)?.getTime() || 0));
  },

  async deleteAccommodation(tripId: string, id: string): Promise<void> {
    await deleteDoc(doc(db, `${TRIPS_COLLECTION}/${tripId}/accommodation_confirmed`, id));
  },

  // TRANSPORT
  async getTransports(tripId: string): Promise<TransportConfirmed[]> {
    const q = collection(db, `${TRIPS_COLLECTION}/${tripId}/transport_confirmed`);
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => {
      const data = doc.data();
      return {
        ...data,
        id: doc.id,
        departure: toDate(data.departure) || new Date(),
        arrival: toDate(data.arrival) || new Date(),
        createdAt: toDate(data.createdAt) || new Date(),
      } as unknown as TransportConfirmed;
    }).sort((a, b) => ((a.departure as Date)?.getTime() || 0) - ((b.departure as Date)?.getTime() || 0));
  },

  async updateTransportPassengers(tripId: string, transportId: string, newPassengers: string[]): Promise<void> {
    const ref = doc(db, `${TRIPS_COLLECTION}/${tripId}/transport_confirmed`, transportId);
    await updateDoc(ref, {
      passengers: newPassengers,
      updatedAt: serverTimestamp(),
    });
  },

  async deleteTransport(tripId: string, id: string): Promise<void> {
    await deleteDoc(doc(db, `${TRIPS_COLLECTION}/${tripId}/transport_confirmed`, id));
  },

  // INVENTORY
  async getInventory(tripId: string): Promise<InventoryConfirmed[]> {
    const q = collection(db, `${TRIPS_COLLECTION}/${tripId}/inventory_confirmed`);
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => {
      const data = doc.data();
      return {
        ...data,
        id: doc.id,
        createdAt: toDate(data.createdAt) || new Date(),
      } as unknown as InventoryConfirmed;
    }).sort((a, b) => ((a.createdAt as Date)?.getTime() || 0) - ((b.createdAt as Date)?.getTime() || 0));
  },

  async updateInventoryStatus(tripId: string, inventoryId: string, updates: Partial<InventoryConfirmed>): Promise<void> {
    const ref = doc(db, `${TRIPS_COLLECTION}/${tripId}/inventory_confirmed`, inventoryId);
    await updateDoc(ref, {
      ...updates,
      updatedAt: serverTimestamp(),
    });
  },

  async deleteInventory(tripId: string, id: string): Promise<void> {
    await deleteDoc(doc(db, `${TRIPS_COLLECTION}/${tripId}/inventory_confirmed`, id));
  },

  // CREATION METHODS
  async createAccommodation(tripId: string, userId: string, data: AccommodationInput): Promise<string> {
    if (data.requiresVoting) {
      const { requiresVoting: _rv, ...proposalData } = data;
      return proposalsService.createProposal(tripId, "accommodation", userId, proposalData);
    }

    const ref = collection(db, `${TRIPS_COLLECTION}/${tripId}/accommodation_confirmed`);
    const newDocRef = doc(ref);
    const { requiresVoting: _rv2, ...confirmedData } = data;

    await setDoc(newDocRef, {
      ...confirmedData,
      id: newDocRef.id,
      createdBy: userId,
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
    });
    return newDocRef.id;
  },

  async createTransport(tripId: string, userId: string, data: TransportInput): Promise<string> {
    if (data.requiresVoting) {
      const { requiresVoting: _rv, ...proposalData } = data;
      return proposalsService.createProposal(tripId, "transport", userId, proposalData);
    }

    const ref = collection(db, `${TRIPS_COLLECTION}/${tripId}/transport_confirmed`);
    const newDocRef = doc(ref);
    const { requiresVoting: _rv2, ...confirmedData } = data;

    await setDoc(newDocRef, {
      ...confirmedData,
      id: newDocRef.id,
      passengers: [],
      createdBy: userId,
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
    });
    return newDocRef.id;
  },

  async createInventory(tripId: string, userId: string, data: InventoryInput): Promise<string> {
    if (data.requiresVoting) {
      const { requiresVoting: _rv, ...proposalData } = data;
      return proposalsService.createProposal(tripId, "inventory", userId, proposalData);
    }

    const ref = collection(db, `${TRIPS_COLLECTION}/${tripId}/inventory_confirmed`);
    const newDocRef = doc(ref);
    const { requiresVoting: _rv2, ...confirmedData } = data;

    await setDoc(newDocRef, {
      ...confirmedData,
      id: newDocRef.id,
      status: "needed",
      assignedTo: null,
      createdBy: userId,
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
    });
    return newDocRef.id;
  },
};

