import {
  collection,
  doc,
  setDoc,
  getDocs,
  deleteDoc,
  serverTimestamp,
  updateDoc,
  Timestamp,
} from "firebase/firestore";
import { db } from "@/lib/firebase";
import type { Role } from "@/types/models"; // only for types if needed

const TRIPS_COLLECTION = "trips";

export type ProposalType = "activity" | "accommodation" | "transport" | "inventory";

export interface UnifiedProposal {
  id: string;
  type: ProposalType;
  title: string;
  description: string | null;
  createdBy: string;
  createdAt: Date;
  updatedAt: Date | null;
  votes: Record<string, string>;
  rawData: any; // Entire original doc
}

export const proposalsService = {
  /**
   * Obtiene todas las propuestas pendientes de las 4 subcolecciones.
   */
  async getAllProposals(tripId: string): Promise<UnifiedProposal[]> {
    const collectionsMap: Record<ProposalType, string> = {
      activity: "activities_proposals",
      accommodation: "accommodation_proposals",
      transport: "transport_proposals",
      inventory: "inventory_proposals",
    };

    const promises = Object.entries(collectionsMap).map(async ([type, collName]) => {
      const collRef = collection(db, `${TRIPS_COLLECTION}/${tripId}/${collName}`);
      const snapshot = await getDocs(collRef);
      console.log(`[SERVICE_DEBUG] fetched ${snapshot.docs.length} docs from ${collName}`);
      return snapshot.docs.map((doc) => {
        const data = doc.data();
        let title = data.title || data.name || "Sin T├¡tulo";

        return {
          id: doc.id,
          type: type as ProposalType,
          title,
          description: data.description || null,
          createdBy: data.createdBy,
          createdAt: data.createdAt instanceof Timestamp ? data.createdAt.toDate() : new Date(),
          updatedAt: data.updatedAt instanceof Timestamp ? data.updatedAt.toDate() : null,
          votes: data.votes || {},
          rawData: data,
        } as UnifiedProposal;
      });
    });

    const results = await Promise.all(promises);
    const flattened = results.flat();
    console.log(`[SERVICE_DEBUG] flattened proposals total: ${flattened.length}`);


    // Sort desc by createdAt
    return flattened.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
  },

  /**
   * Crea una nueva propuesta en la subcolecci├│n correspondiente
   */
  async createProposal(tripId: string, type: ProposalType, userId: string, data: any): Promise<string> {
    const collName = this.getCollectionNameForType(type);
    const ref = collection(db, `${TRIPS_COLLECTION}/${tripId}/${collName}`);
    const newDocRef = doc(ref);

    const baseData = {
      id: newDocRef.id,
      createdBy: userId,
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
      votes: { [userId]: "yes" }, // Creador vota a favor por defecto
      status: "pending",
      ...data,
    };

    await setDoc(newDocRef, baseData);
    return newDocRef.id;
  },

  /**
   * Actualiza una propuesta existente en la subcolecci├│n correspondiente
   */
  async updateProposal(tripId: string, type: ProposalType, proposalId: string, data: any): Promise<void> {
    const collName = this.getCollectionNameForType(type);
    const ref = doc(db, `${TRIPS_COLLECTION}/${tripId}/${collName}`, proposalId);

    // Filter out undefined values to avoid Firebase errors
    const cleanData = Object.fromEntries(
      Object.entries(data).filter(([_, v]) => v !== undefined)
    );

    await updateDoc(ref, {
      ...cleanData,
      updatedAt: serverTimestamp(),
    });
  },


  /**
   * Elimina una propuesta seg├║n su ID y Tipo
   */
  async deleteProposal(tripId: string, type: ProposalType, proposalId: string): Promise<void> {
    const collName = this.getCollectionNameForType(type);
    const ref = doc(db, `${TRIPS_COLLECTION}/${tripId}/${collName}`, proposalId);
    await deleteDoc(ref);
  },

  /**
   * Confirma una propuesta, migr├índola a la colecci├│n definitiva ("_confirmed" o "events")
   * y elimin├índola de la bandeja de propuestas ("_proposals").
   */
  async confirmProposal(tripId: string, type: ProposalType, proposalId: string, rawData: any): Promise<void> {
    let targetCollection = "";
    let formattedData: any = {
      ...rawData,
      updatedAt: serverTimestamp(),
    };

    // Prevent 'votes' from polluting the confirmed document if not needed,
    // though for MVP keeping it doesn't break anything. We remove it for clean data.
    delete formattedData.votes;
    delete formattedData.status; // Pending status no longer needed

    if (type === "activity") {
      targetCollection = "events";
      // Ensure 'category' is set for events if not present
      formattedData.category = formattedData.category || "activity";
      // Ensure 'rsvp' mapping exists
      formattedData.rsvp = {};
    } else if (type === "accommodation") {
      targetCollection = "accommodation_confirmed";
    } else if (type === "transport") {
      targetCollection = "transport_confirmed";
      formattedData.passengers = []; // Initialize empty passengers
      // capacity is expected from rawData or defaults
      formattedData.capacity = rawData.capacity || 0;
    } else if (type === "inventory") {
      targetCollection = "inventory_confirmed";
      formattedData.status = "needed";
      formattedData.assignedTo = null;
    }

    const targetRef = doc(db, `${TRIPS_COLLECTION}/${tripId}/${targetCollection}`, proposalId);
    await setDoc(targetRef, formattedData);

    // Delete the original proposal
    await this.deleteProposal(tripId, type, proposalId);
  },

  /**
   * Modifica el voto en una propuesta. 
   * Firebase no permite merge f├ícil en objetos anidados sin usar set con merge, 
   * o dot notation updateDoc({"votes.userId": voteValue})
   */
  async voteProposal(tripId: string, type: ProposalType, proposalId: string, userId: string, voteValue: string): Promise<void> {
    const collName = this.getCollectionNameForType(type);
    const ref = doc(db, `${TRIPS_COLLECTION}/${tripId}/${collName}`, proposalId);

    await updateDoc(ref, {
      [`votes.${userId}`]: voteValue
    });
  },

  /**
   * Utils interno
   */
  getCollectionNameForType(type: ProposalType): string {
    switch (type) {
      case "activity": return "activities_proposals";
      case "accommodation": return "accommodation_proposals";
      case "transport": return "transport_proposals";
      case "inventory": return "inventory_proposals";
      default: throw new Error(`Unknown proposal type ${type}`);
    }
  }
};

import React, { useState } from "react";
import { useForm } from "react-hook-form";
import { NeumorphicInput } from "@/components/neumorphic/NeumorphicInput";
import { NeumorphicButton } from "@/components/neumorphic/NeumorphicButton";
import { useCreateProposal, useUpdateProposal } from "@/features/proposals/hooks/useProposals";
import { useAuthStore } from "@/features/auth/stores/useAuthStore";
import { Timestamp } from "firebase/firestore";
import { UnifiedProposal } from "@/features/proposals/api/proposalsService";

interface AccommodationProposalFormProps {
  tripId: string;
  initialData?: UnifiedProposal;
  onSuccess: () => void;
  onCancel: () => void;
}


export function AccommodationProposalForm({
  tripId,
  initialData,
  onSuccess,
  onCancel,
}: AccommodationProposalFormProps) {
  const { currentUser } = useAuthStore();
  const { mutateAsync: createProposal } = useCreateProposal(tripId);
  const { mutateAsync: updateProposal } = useUpdateProposal(tripId);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isEdit = !!initialData;

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm({
    defaultValues: {
      title: initialData?.title || "",
      location: initialData?.rawData?.location || "",
      checkIn: initialData?.rawData?.checkIn instanceof Timestamp 
        ? initialData.rawData.checkIn.toDate().toISOString().split("T")[0] 
        : "",
      checkOut: initialData?.rawData?.checkOut instanceof Timestamp 
        ? initialData.rawData.checkOut.toDate().toISOString().split("T")[0] 
        : "",
      priceEstimate: initialData?.rawData?.priceEstimate || "",
      notes: initialData?.description || "",
    },
  });

  const onSubmit = async (values: Record<string, any>) => {
    if (!currentUser) return;
    setIsSubmitting(true);
    setError(null);
    try {
      const proposalData = {
        title: values.title,
        location: values.location || null,
        checkIn: values.checkIn
          ? Timestamp.fromDate(new Date(values.checkIn + "T12:00:00"))
          : null,
        checkOut: values.checkOut
          ? Timestamp.fromDate(new Date(values.checkOut + "T12:00:00"))
          : null,
        priceEstimate: values.priceEstimate ? Number(values.priceEstimate) : null,
        notes: values.notes || null,
      };

      if (isEdit) {
        await updateProposal({
          type: "accommodation",
          proposalId: initialData!.id,
          data: proposalData,
        });
      } else {
        await createProposal({
          type: "accommodation",
          userId: currentUser.uid,
          data: proposalData,
        });
      }
      onSuccess();
    } catch (e) {
