        label="Categor├¡a"
        type="select"
        options={[
          { label: "General", value: "general" },
          { label: "Electr├│nica", value: "electronica" },
          { label: "Salud / Farmacia", value: "salud" },
          { label: "Comida / Bebida", value: "comida" },
          { label: "Documentaci├│n", value: "documentacion" },
          { label: "Ropa / Equipo", value: "equipo" },
