import { useAuthStore } from "@/features/auth/stores/useAuthStore";
import { Timestamp } from "firebase/firestore";
import { UnifiedProposal } from "@/features/proposals/api/proposalsService";

interface TransportProposalFormProps {
  tripId: string;
  initialData?: UnifiedProposal;
  onSuccess: () => void;
  onCancel: () => void;
}

export function TransportProposalForm({
  tripId,
  initialData,
  onSuccess,
  onCancel,
}: TransportProposalFormProps) {
  const { currentUser } = useAuthStore();
  const { mutateAsync: createProposal } = useCreateProposal(tripId);
  const { mutateAsync: updateProposal } = useUpdateProposal(tripId);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isEdit = !!initialData;

  const {
    register,
    handleSubmit,
    watch,
    control,
    formState: { errors },
  } = useForm({
    defaultValues: {
      title: initialData?.title || "",
      departure:
        initialData?.rawData?.departure instanceof Timestamp
          ? initialData.rawData.departure.toDate().toISOString().split("T")[0]
          : "",
      arrival:
        initialData?.rawData?.arrival instanceof Timestamp
          ? initialData.rawData.arrival.toDate().toISOString().split("T")[0]
          : "",
      isPersonal: initialData?.rawData?.isPersonal || false,
      capacity: initialData?.rawData?.capacity || 4,
      priceEstimate: initialData?.rawData?.priceEstimate || "",
      notes: initialData?.description || "",
    },
  });

  const isPersonal = watch("isPersonal");

  const onSubmit = async (values: Record<string, any>) => {
    if (!currentUser) return;
    setIsSubmitting(true);
    setError(null);
    try {
      const proposalData = {
        title: values.title,
        departure: values.departure
          ? Timestamp.fromDate(new Date(values.departure + "T12:00:00"))
          : null,
        arrival: values.arrival ? Timestamp.fromDate(new Date(values.arrival + "T12:00:00")) : null,
        isPersonal: values.isPersonal,
        capacity: values.isPersonal ? Number(values.capacity) : null,
        priceEstimate: values.priceEstimate ? Number(values.priceEstimate) : null,
        notes: values.notes || null,
      };

      if (isEdit) {
        await updateProposal({
          type: "transport",
          proposalId: initialData!.id,
          data: proposalData,
        });
      } else {
        await createProposal({
          type: "transport",
          userId: currentUser.uid,
          data: proposalData,
        });
      }
      onSuccess();
    } catch (e) {
      console.error(e);
      setError("Error al guardar propuesta");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
      <NeumorphicInput
        label="Medio de Transporte"
        placeholder="Ej: Auto de Juan, Vuelo LATAM, Tren..."
        error={errors.title?.message as string}
        required
        {...register("title", { required: "El t├¡tulo es obligatorio" })}
      />

      <div className="grid grid-cols-2 gap-4">
        <NeumorphicInput label="Fecha de Salida" type="date" {...register("departure")} />
        <NeumorphicInput label="Fecha de Llegada" type="date" {...register("arrival")} />
      </div>

      <Controller
        name="isPersonal"
        control={control}
        render={({ field }) => (
          <NeumorphicToggle
            checked={field.value}
            onChange={field.onChange}
            label="┬┐Es transporte personal? (Ej. Mi auto)"
            className="px-1"
          />
        )}
      />

      {isPersonal && (
        <div className="animate-in fade-in slide-in-from-top-2">
          <NeumorphicInput
            label="Capacidad (Cant de Pasajeros)"
            type="number"
            min="1"
            {...register("capacity", { min: 1 })}
          />
        </div>
      )}

      <NeumorphicInput
        label="Costo Estimado"
        type="number"
        placeholder="0.00"
        {...register("priceEstimate")}
      />

      <NeumorphicInput
        label="Notas adicionales"
        type="textarea"
        placeholder="Cualquier detalle extra..."
        {...register("notes")}
      />

      {error && <div className="text-red-500 text-sm text-center">{error}</div>}

      <NeumorphicButton type="submit" variant="primary" className="mt-6" disabled={isSubmitting}>
        {isSubmitting ? "Guardando..." : isEdit ? "Guardar Cambios" : "Sugerir Transporte"}
      </NeumorphicButton>
    </form>
  );
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { proposalsService, ProposalType } from "../api/proposalsService";

const PROPOSALS_KEY = "trip-proposals";

export const useAllProposals = (tripId: string) => {
  return useQuery({
    queryKey: [PROPOSALS_KEY, tripId],
    queryFn: async () => {
      try {
        const data = await proposalsService.getAllProposals(tripId);
        return data;
      } catch (err) {
        console.error("Error fetching proposals in React Query:", err);
        throw err;
      }
    },
    enabled: !!tripId,
  });
};

export const useCreateProposal = (tripId: string) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ type, userId, data }: { type: ProposalType, userId: string, data: any }) => 
      proposalsService.createProposal(tripId, type, userId, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [PROPOSALS_KEY, tripId] });
    },
  });
};

export const useUpdateProposal = (tripId: string) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ type, proposalId, data }: { type: ProposalType, proposalId: string, data: any }) => 
      proposalsService.updateProposal(tripId, type, proposalId, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [PROPOSALS_KEY, tripId] });
    },
  });
};


export const useVoteProposal = (tripId: string) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ type, proposalId, userId, vote }: { type: ProposalType, proposalId: string, userId: string, vote: string }) => 
      proposalsService.voteProposal(tripId, type, proposalId, userId, vote),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [PROPOSALS_KEY, tripId] });
    },
  });
};

export const useDeleteProposal = (tripId: string) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ type, proposalId }: { type: ProposalType, proposalId: string }) => 
      proposalsService.deleteProposal(tripId, type, proposalId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [PROPOSALS_KEY, tripId] });
    },
  });
};

export const useConfirmProposal = (tripId: string) => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ type, proposalId, rawData }: { type: ProposalType, proposalId: string, rawData: any }) => 
      proposalsService.confirmProposal(tripId, type, proposalId, rawData),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [PROPOSALS_KEY, tripId] });
      // We also invalidate itinerary items because confirming shifts items to timeline or logistics
      queryClient.invalidateQueries({ queryKey: ["itinerary-items", tripId] });
      queryClient.invalidateQueries({ queryKey: ["backlog-activities", tripId] });
    },
  });
};

"use client";

import React, { useState } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { NeumorphicInput } from "@/components/neumorphic/NeumorphicInput";
import { NeumorphicButton } from "@/components/neumorphic/NeumorphicButton";
import { RequiresVotingSelector } from "../RequiresVotingSelector";
import { createActivitySchema, type CreateActivityInput } from "../../types";
import { tripService } from "../../api";
import { useAuthStore } from "@/features/auth/stores/useAuthStore";
import { Icon } from "@/components/ui/Icon";

interface ActivityFormProps {
  tripId: string;
  mode?: "direct" | "proposal";
  onSuccess: () => void;
}

export function ActivityForm({ tripId, mode = "direct", onSuccess }: ActivityFormProps) {

  const { currentUser } = useAuthStore();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
    register,
    handleSubmit,
    control,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(createActivitySchema),
    defaultValues: {
      requiresVoting: mode === "proposal",
      title: "",
      location: "",
      costImpact: null,
      date: null,
      startTime: "",
      description: "",
    },
  });

  const onSubmit = async (values: any) => {
    const data = values as CreateActivityInput;
    if (!currentUser) {
      setError("Debes estar autenticado");
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      if (data.requiresVoting) {
        await tripService.createProposal(tripId, currentUser.uid, data);
      } else {
        await tripService.createActivity(tripId, currentUser.uid, data);
      }
      onSuccess();
    } catch (err) {
      console.error("Error creating activity/proposal:", err);
      setError("Error al crear. Intenta de nuevo.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
      <NeumorphicInput
        label="T├¡tulo de la Actividad"
        placeholder="Ej: Cena en el puerto"
        error={errors.title?.message}
        required
        {...register("title")}
      />

      <NeumorphicInput
        label="Ubicaci├│n"
        placeholder="Ej: Restaurante La Marina"
        error={errors.location?.message}
        {...register("location")}
      />

      <div className="grid grid-cols-2 gap-4">
        <NeumorphicInput
          label="Fecha"
          type="date"
          error={errors.date?.message}
          {...register("date", { valueAsDate: true })}
        />
        <NeumorphicInput
          label="Hora"
          type="time"
          error={errors.startTime?.message}
          {...register("startTime")}
        />
      </div>

      <NeumorphicInput
        label="Costo Estimado"
        type="number"
        placeholder="0.00"
        error={errors.costImpact?.message}
        {...register("costImpact")}
      />

      <NeumorphicInput
        label="Notas adicionales"
        type="textarea"
        placeholder="Cualquier detalle extra..."
        error={errors.description?.message}
        {...register("description")}
      />

      <p className="flex items-center gap-2 border p-2 rounded-lg text-sm text-primary-extralight bg-primary-extralight/10">
        <Icon name="info" />
        Se mostrar├í en el itinerario si tiene fecha asignada.
      </p>

      {mode !== "proposal" && (
        <div className="pt-2">
          <Controller
            name="requiresVoting"
            control={control}
            render={({ field }) => (
              <RequiresVotingSelector value={field.value} onChange={field.onChange} />
            )}
          />
        </div>
      )}

      {error && (
        <div className="p-3 bg-danger/10 border border-danger/20 rounded-xl text-danger text-sm text-center">
          {error}
        </div>
      )}

      <NeumorphicButton
        type="submit"
        variant="primary"
        className="flex-1 bg-primary text-white"
        disabled={isSubmitting}
      >
        {isSubmitting ? "Guardando..." : "Crear Actividad"}
      </NeumorphicButton>
    </form>
  );
}

"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { NeumorphicInput } from "@/components/neumorphic/NeumorphicInput";
import { NeumorphicButton } from "@/components/neumorphic/NeumorphicButton";
import { createTripSchema, type CreateTripInput } from "../../types";
import { tripService } from "../../api";
import { useAuthStore } from "@/features/auth/stores/useAuthStore";
import { useState } from "react";
import type { CreateTripFormProps } from "./CreateTripForm.types";
import { uploadToCloudinary } from "@/lib/cloudinary";

export function CreateTripForm({ onSuccess, onCancel }: CreateTripFormProps) {
  const { currentUser } = useAuthStore();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
    register,
    handleSubmit,
    formState: { errors },
    setValue,
  } = useForm<CreateTripInput>({
    resolver: zodResolver(createTripSchema),
    defaultValues: {
      currency: "USD",
    },
  });

  const onSubmit = async (data: CreateTripInput) => {
    if (!currentUser) {
      setError("Debes estar autenticado para crear un viaje");
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      const tripId = await tripService.createTrip(currentUser.uid, data);
      onSuccess?.(tripId);
    } catch (err) {
      console.error("Error creating trip:", err);
      setError("Hubo un error al crear el viaje. Intenta de nuevo.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
      <NeumorphicInput
        label="Nombre del Viaje"
        placeholder="Ej: Expedici├│n Patagonia"
        error={errors.name?.message}
        required
        {...register("name")}
      />

      <div className="grid grid-cols-2 gap-4">
        <NeumorphicInput
          label="Fecha de Inicio"
          type="date"
          error={errors.startDate?.message}
          {...register("startDate", { valueAsDate: true })}
        />
        <NeumorphicInput
          label="Fecha de Fin"
          type="date"
          error={errors.endDate?.message}
          {...register("endDate", { valueAsDate: true })}
        />
      </div>

      <NeumorphicInput
        label="Moneda Principal"
        type="select"
        options={[
          { value: "ARS", label: "Peso Argentino (ARS)" },
          { value: "USD", label: "D├│lar Estadounidense (USD)" },
          { value: "EUR", label: "Euro (EUR)" },
          { value: "BRL", label: "Real Brasile├▒o (BRL)" },
          { value: "CLP", label: "Peso Chileno (CLP)" },
          { value: "UYU", label: "Peso Uruguayo (UYU)" },
        ]}
        error={errors.currency?.message}
        required
        {...register("currency")}
      />

      <div className="flex flex-col gap-2">
        <NeumorphicInput
          type="file"
          label="Portada"
          placeholder={isSubmitting ? "Subiendo..." : "Seleccionar imagen"}
          onChange={async (e: React.ChangeEvent<HTMLInputElement>) => {
            const file = e.target.files?.[0];
            if (file) {
              setIsSubmitting(true);
              try {
                const url = await uploadToCloudinary(file);
                setValue("coverImage", url);
              } catch (error) {
                console.error("Error al subir la imagen:", error);
              } finally {
                setIsSubmitting(false);
              }
            }
          }}
        />
      </div>

      <NeumorphicInput
        label="Descripci├│n"
        type="textarea"
        placeholder="Cu├®ntanos m├ís..."
        error={errors.description?.message}
        {...register("description")}
      />

      {error && (
        <div className="p-3 bg-danger/10 border border-danger/20 rounded-xl text-danger text-sm text-center">
          {error}
        </div>
      )}
      <NeumorphicButton
        type="submit"
        variant="primary"
        className="shadow-neumorphic-sm! bg-primary text-white"
        disabled={isSubmitting}
      >
        {isSubmitting ? "Creando..." : "Crear Viaje"}
      </NeumorphicButton>
    </form>
  );
}

"use client";

import { NeumorphicCard } from "@/components/neumorphic/NeumorphicCard";
import { CreateTripForm } from "../CreateTripForm";
import { Icon } from "@/components/ui/Icon";
import type { CreateTripModalProps } from "./CreateTripModal.types";
import { Modal } from "@/components/ui/dialog/Modal";

export function CreateTripModal({ isOpen, onClose }: CreateTripModalProps) {
  if (!isOpen) return null;

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Crear Nuevo Viaje"
      description="Completa los datos de tu viaje."
    >
      <CreateTripForm
        onSuccess={() => {
          onClose();
          window.location.reload();
        }}
        onCancel={onClose}
      />
    </Modal>
  );
}

"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { NeumorphicInput } from "@/components/neumorphic/NeumorphicInput";
import { NeumorphicButton } from "@/components/neumorphic/NeumorphicButton";
import { createTripSchema } from "../../types";
import { z } from "zod";
import { tripService } from "../../api";

import { useState } from "react";
import type { EditTripFormProps } from "./EditTripForm.types";
import { uploadToCloudinary } from "@/lib/cloudinary";
import { Timestamp } from "firebase/firestore";
import { NeumorphicCard } from "@/components/neumorphic/NeumorphicCard";

export function EditTripForm({ trip, userRole, onSuccess, onDelete }: EditTripFormProps) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Helper para convertir fecha a string YYYY-MM-DD
  const formatDateForInput = (dateValue: Timestamp | Date | null | undefined) => {
    if (!dateValue) return "";
    let d = dateValue;
    if ((d as Timestamp).toDate) {
      d = (d as Timestamp).toDate();
    } else {
      d = new Date(d as string | Date);
    }
    return (d as Date).toISOString().split("T")[0];
  };

  const {
    register,
    handleSubmit,
    formState: { errors },
    setValue,
    watch,
  } = useForm<z.input<typeof createTripSchema>>({
    resolver: zodResolver(createTripSchema),
    defaultValues: {
      name: trip.name,
      description: trip.description || "",
      startDate: formatDateForInput(trip.startDate),
      endDate: formatDateForInput(trip.endDate),
      currency: trip.currency || "USD",
      coverImage: trip.coverImage || "",
      dailyBudget: trip.dailyBudget ?? undefined,
    },
  });

  const coverImage = watch("coverImage");

  const onSubmit = async (data: z.infer<typeof createTripSchema>) => {
    setIsSubmitting(true);
    setError(null);

    try {
      await tripService.updateTrip(trip.id, data);
      onSuccess?.();
    } catch (err) {
      console.error("Error updating trip:", err);
      setError("Hubo un error al guardar los cambios. Intenta de nuevo.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (userRole !== "owner") return;
    if (
      !window.confirm("┬┐Seguro que deseas eliminar este viaje? Esta acci├│n no se puede deshacer.")
    )
      return;

    setIsDeleting(true);
    setError(null);
    try {
      await tripService.deleteTrip(trip.id);
      onDelete?.(); // Ejecuta callback usualmente redirigiendo a "/"
    } catch (err) {
      console.error("Error deleting trip:", err);
      setError("Hubo un error al eliminar el viaje.");
      setIsDeleting(false);
    }
  };

  return (
    <NeumorphicCard>
      <form onSubmit={handleSubmit((data: any) => onSubmit(data))} className="space-y-6">
        <NeumorphicInput
          label="Nombre del Viaje"
          placeholder="Ej: Expedici├│n Patagonia"
          error={errors.name?.message}
          required
          {...register("name")}
        />

        <div className="grid grid-cols-2 gap-4">
          <NeumorphicInput
            label="Fecha de Inicio"
            type="date"
            error={errors.startDate?.message}
            {...register("startDate", { valueAsDate: true })}
          />
          <NeumorphicInput
            label="Fecha de Fin"
            type="date"
            error={errors.endDate?.message}
            {...register("endDate", { valueAsDate: true })}
          />
        </div>

        <NeumorphicInput
          label="Moneda Principal"
          type="select"
          options={[
            { value: "ARS", label: "Peso Argentino (ARS)" },
            { value: "USD", label: "D├│lar Estadounidense (USD)" },
            { value: "EUR", label: "Euro (EUR)" },
            { value: "BRL", label: "Real Brasile├▒o (BRL)" },
            { value: "CLP", label: "Peso Chileno (CLP)" },
            { value: "UYU", label: "Peso Uruguayo (UYU)" },
          ]}
          error={errors.currency?.message}
          required
          {...register("currency")}
        />

        <div className="flex flex-col gap-2">
          {coverImage && (
            <div className="flex flex-col gap-1 mb-2">
              <label className="font-display text-sm font-semibold text-main ml-2">Portada</label>
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={coverImage}
                alt="Portada del viaje"
                className="w-full h-[120px] object-cover rounded-2xl shadow-sm"
              />
            </div>
          )}
          <NeumorphicInput
            type="file"
            label="Cambiar Portada"
            placeholder={isSubmitting ? "Subiendo..." : "Seleccionar imagen"}
            onChange={async (e: React.ChangeEvent<HTMLInputElement>) => {
              const file = e.target.files?.[0];
              if (file) {
                setIsSubmitting(true);
                try {
                  const url = await uploadToCloudinary(file);
                  setValue("coverImage", url);
                } catch (error) {
                  console.error("Error al subir la imagen:", error);
                } finally {
                  setIsSubmitting(false);
                }
              }
            }}
          />
        </div>

        <NeumorphicInput
          label="Descripci├│n"
          type="textarea"
          placeholder="Cu├®ntanos m├ís..."
          error={errors.description?.message}
          {...register("description")}
        />

        {error && (
          <div className="p-3 bg-danger/10 border border-danger/20 rounded-xl text-danger text-sm text-center">
            {error}
          </div>
        )}

        <NeumorphicButton
          type="submit"
          variant="primary"
          className="w-full shadow-neumorphic-sm! bg-[#F46A1F] text-white"
          disabled={isSubmitting || isDeleting}
        >
          {isSubmitting ? "Guardando..." : "Guardar Cambios"}
        </NeumorphicButton>

        {userRole === "owner" && (
          <NeumorphicButton
            type="button"
            onClick={handleDelete}
            disabled={isSubmitting || isDeleting}
            variant="danger"
          >
            <span className="material-symbols-rounded text-[20px]">delete</span>
            {isDeleting ? "Eliminando..." : "Eliminar Viaje"}
          </NeumorphicButton>
        )}
      </form>
    </NeumorphicCard>
  );
}
